    '',
    '// Topo mode: banded contour lines from FBM noise.',
    '// Shares the kaleido + domain warp + background gradient + palette infrastructure',
    '// with Lines mode, so palette / post-FX / archetypes work identically across both.',
    'vec3 topoColor(vec2 uv) {',
    '  vec2 muv = kaleido(uv, u_kaleidoscopeSegments);',
    '  vec2 space = (muv - 0.5) * 2.0 * u_scale * vec2(1.0, u_resolution.y / u_resolution.x);',
    '  space = domainWarp(space, u_domainWarpDepth, u_domainWarpScale, u_domainWarpAmplitude);',
    '',
    '  // Sample FBM at noise-scale-zoomed, time-drifted coords.',
    '  vec2 p = space * u_noiseScale + vec2(u_time * u_driftSpeed, u_time * u_driftSpeed * 0.4);',
    '  float h = fbmN(p, u_fbmOctaves);',
