    '  // Convert the height field into contour bands.',
    '  // band = sawtooth across [0,1]; ridge = triangle wave peaking at band centres.',
    '  float band = fract(h * u_bandCount);',
    '  float ridge = min(band, 1.0 - band) * 2.0;',
    '',
    '  // The contour LINE is where ridge ~ 0 (i.e. the band edges). Use thickness + softness',
    '  // to control how wide and how feathered each contour edge is.',
    '  float thicknessHalf = clamp(u_bandThickness, 0.001, 0.5);',
    '  float softness = max(u_bandSoftness * thicknessHalf, 0.001);',
    '  float contour = 1.0 - smoothstep(thicknessHalf - softness, thicknessHalf + softness, ridge);',
