    '      // pulses: periodic expanding/fading glow at points along each line.',
    '      float pulsePhase = mod(u_time * u_accentSpeed * 0.8 + fl * 1.7, 2.0);',
    '      float pulseRadius = u_accentSize * (0.4 + pulsePhase * 1.6);',
    '      float pulseFade = (1.0 - smoothstep(0.5, 2.0, pulsePhase)) * smoothstep(0.0, 0.3, pulsePhase);',
    '      float pulseSpacing = max(u_circleSpacing * 0.6, 4.0);',
    '      float pulseX = mod(fl * 0.7 + u_time * u_overallSpeed * u_accentSpeed * 0.3, pulseSpacing) - pulseSpacing * 0.5;',
    '      vec2 pulsePos = vec2(pulseX, getPlasmaY(pulseX, horizontalFade, offset));',
