    '    } else if (u_accentType < 1.5) {',
    '      // sparks: bright tight points spawning at random along the line, short lifetime.',
    '      float sparkPhase = u_time * u_accentSpeed * 2.5 + fl * 2.3;',
    '      float sparkCycle = floor(sparkPhase);',
    '      float sparkLife  = fract(sparkPhase);',
    '      float sparkX = random(fl + sparkCycle * 1.7) * u_circleSpacing * 0.8;',
    '      float sparkFade = smoothstep(0.0, 0.1, sparkLife) * (1.0 - smoothstep(0.4, 1.0, sparkLife));',
    '      vec2 sparkPos = vec2(sparkX, getPlasmaY(sparkX, horizontalFade, offset));',
    '      accent = drawCircle(sparkPos, u_accentSize * 0.6, space) * sparkFade * (u_accentDensity * 5.0);',
