    '      // comets: v1 back-compat — uses circleRadius/Brightness/Spacing for byte-identical 1a behaviour.',
    '      float circleX = mod(fl + u_time * lineSpeed * u_accentSpeed, u_circleSpacing) - u_circleSpacing * 0.48;',
    '      vec2 circlePosition = vec2(circleX, getPlasmaY(circleX, horizontalFade, offset));',
