    '    } else if (u_accentType < 3.5) {',
    '      // bloom: bright nodes that pulse gently. Reads brightest with direction=woven (perpendicular pass adds energy).',
    '      float bloomPhase = u_time * u_accentSpeed * 0.4 + fl * 0.9;',
    '      float bloomPulse = 0.6 + 0.4 * sin(bloomPhase * 6.28318530718);',
    '      float bloomSpacing = max(u_circleSpacing * 0.5, 4.0);',
    '      float bx = mod(fl * 1.3, bloomSpacing) - bloomSpacing * 0.5;',
    '      vec2 bp = vec2(bx, getPlasmaY(bx, horizontalFade, offset));',
    '      accent = drawCircle(bp, u_accentSize * 1.2, space) * bloomPulse * (u_accentDensity * 4.0);',
    '    }',
    '    // accentType >= 3.5 (i.e. "none") → accent stays 0.',
    '',
    '    line = line + accent;',
    '',
    '    vec4 lineColorChoice;',
    '    if (u_paletteMode > 0.5) {',
    '      float pt = normalizedLineIndex + u_time * u_paletteSpeed;',
    '      vec3 palCol = iqPalette(pt, u_paletteA, u_paletteB, u_paletteC, u_paletteD);',
    '      lineColorChoice = vec4(palCol, u_lineColor.a);',
    '    } else {',
    '      lineColorChoice = u_lineColor;',
    '    }',
    '',
    '    lines += line * lineColorChoice * rand;',
    '  }',
    '  return lines;',
    '}',
    '',
    'vec3 patternColor(vec2 uv) {',
    '  // Dispatch on mode. u_mode is a uniform — flips instantly, no recompile.',
    '  if (u_mode > 0.5) return topoColor(uv);',
    '',
    '  // 1. Optional kaleidoscope UV transform.',
    '  vec2 muv = kaleido(uv, u_kaleidoscopeSegments);',
    '',
    '  // 2. World-space coord (matches v1 aspect handling: scaled by 1/width on both axes).',
    '  vec2 space = (muv - 0.5) * 2.0 * u_scale * vec2(1.0, u_resolution.y / u_resolution.x);',
    '',
    '  // 3. Optional IQ-style domain warp BEFORE the plasma\'s own line warp.',
    '  space = domainWarp(space, u_domainWarpDepth, u_domainWarpScale, u_domainWarpAmplitude);',
    '',
    '  float horizontalFade = 1.0 - (cos(muv.x * 6.28) * 0.5 + 0.5);',
    '  float verticalFade   = 1.0 - (cos(muv.y * 6.28) * 0.5 + 0.5);',
    '',
    '  // 4. Direction-family dispatch. Uniform-branched, instant switching.',
    '  //    horizontal = v1 behaviour; vertical = axis-swap; diagonal = rotate by lineAngle;',
    '  //    radial = polar around radialCenter; woven = horizontal + vertical blended.',
    '  vec4 lines;',
    '  if (u_lineDirection < 0.5) {',
    '    lines = linePass(space, horizontalFade);',
    '  } else if (u_lineDirection < 1.5) {',
    '    lines = linePass(vec2(space.y, space.x), horizontalFade);',
    '  } else if (u_lineDirection < 2.5) {',
    '    float a = radians(u_lineAngle);',
    '    float ca = cos(a); float sa = sin(a);',
    '    vec2 rotSpace = vec2(ca * space.x - sa * space.y, sa * space.x + ca * space.y);',
    '    lines = linePass(rotSpace, horizontalFade);',
    '  } else if (u_lineDirection < 3.5) {',
    '    // Radial: UV-space centre → world, then to polar. theta scaled by u_scale so plasma frequency reads similarly across modes.',
    '    vec2 centerWorld = (u_radialCenter - 0.5) * 2.0 * u_scale * vec2(1.0, u_resolution.y / u_resolution.x);',
    '    vec2 p = space - centerWorld;',
    '    float theta = atan(p.y, p.x);',
    '    float r = length(p);',
    '    lines = linePass(vec2(theta * u_scale, r), horizontalFade);',
    '  } else {',
    '    // Woven: pass A in source frame, pass B in axis-swapped frame, blended.',
    '    vec4 ax = linePass(space, horizontalFade);',
    '    vec4 ay = linePass(vec2(space.y, space.x), horizontalFade);',
    '    lines = mix(ax, ay, clamp(u_wovenBlend, 0.0, 1.0));',
    '  }',
